          GP_WB_RANGE_CHECK(val, 0x01); \
          GP_WB_CHECK_OFFSET_CONN_EV_INFO(offset); \
          GP_WB_MWRITE_U8((offset) + GP_WB_CONN_EV_INFO_METRICS_UPDATE_BUSY_ADDRESS, 0x01, (val)); \
